using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class PartsTraining : TrainingContentBase
{
    public PartsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Overview",
            Slug = "parts-overview",
            Summary = "What parts are, the three classification axes (procurement, inventory class, item kind), statuses, BOMs, vendor sources, routing, and how parts connect to jobs, inventory, purchasing, and sales.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","inventory","catalog","sourcing"]""",
            ContentJson = """{"body":"## Parts Catalog Overview\n\nThe Parts Catalog is the central register for every item your shop manufactures, purchases, or stocks. Each part record captures the full engineering definition — what the part is, how it's sourced, where it lives in inventory, and how it's built. Parts connect to nearly every other module: jobs consume parts, inventory tracks their quantities, purchase orders procure them, sales orders sell them, and operations define how to produce them.\n\n### What Is a Part?\n\nA part is any discrete item your business tracks — finished goods, raw materials, sub-assemblies, components, consumables, fasteners, electronics, packaging, and tooling. Every part gets a system-generated part number and a name. New parts start in Draft status and progress through Prototype → Active → Obsolete.\n\n### The Three Classification Axes\n\nA part isn't defined by a single \"type\" — that one field used to overload three distinct concepts. Each part is now classified by **three orthogonal axes**, chosen on the New Part screen:\n\n1. **Procurement Source** — how the part is sourced.\n   - **Make** — produced in-house. May still send out individual operations (subcontract ops).\n   - **Buy** — purchased complete from a vendor.\n   - **Subcontract** — entire part outsourced; the vendor builds it, we never touch it.\n   - **Phantom** — a logical assembly that never physically exists; explodes through to its children for MRP.\n2. **Inventory Class** — which bucket the part lives in.\n   - **Raw**, **Component**, **Subassembly**, **FinishedGood**, **Consumable**, **Tool**.\n3. **Item Kind** — descriptive taxonomy (admin-configurable) such as Fastener, Electronic, Packaging, Hardware, Material.\n\nNot every combination is meaningful — eleven viable (procurement × inventory class) combinations are documented and drive which detail tabs appear, which workflow runs on creation, and which gates fire at promotion time. The detail page's tab layout adapts to the axes automatically.\n\n**Identity axes are immutable after a part is created.** Procurement Source and Inventory Class drive everything downstream — which tabs render, which validators run, which cost calculations are valid. Changing them mid-life would invalidate history. Use a dedicated migration tool if a part truly needs to be reclassified.\n\n### Tier 0 Identity Fields\n\nBeyond the three axes, every part record carries:\n\n- **Traceability** — None (bulk), Lot (by batch), or Serial (per unit). Replaces the old isSerialTracked boolean.\n- **ABC Class** — A/B/C for value-based prioritization (cycle counting frequency, control intensity).\n- **Manufacturer** + **Manufacturer Part Number** — the OEM identity (distinct from a distributor's vendor part number).\n- **Revision** — engineering rev. Defaults to A.\n- **Description** — long-form notes.\n\n### Status Lifecycle\n\nFour statuses gate what the part can do:\n\n- **Draft** — record exists; not visible to production workflows or purchasing.\n- **Prototype** — usable in jobs and inventory but flagged as not finalized.\n- **Active** — fully approved for production, purchasing, and sales. Default for parts that survived their workflow.\n- **Obsolete** — preserved for historical traceability. Won't appear in new orders.\n\nParts are never hard-deleted. Most status moves happen via the Identity cluster's Status field on the detail page — but the one move that matters most, **Draft → Active**, has its own readiness-gated button (see *Promoting a Draft Part to Active* below).\n\n### Promoting a Draft Part to Active\n\nA new part lands as **Draft**. Draft means \"the record exists but isn't finished\" — it's hidden from production workflows and purchasing. To make a part usable everywhere, you promote it to **Active**, and the system checks that the part is actually ready first.\n\nThere are two paths to Active, both running the same readiness gates:\n\n1. **Finish the New Part workflow.** When you click Complete on the last step of the guided/express New Part flow, the server runs the readiness checks. If they all pass, the part is promoted to Active automatically and you land back on the parts list. If something's missing, you get a message naming exactly which step needs attention (e.g., \"Finish 'Routing' before moving on\") and the run stays open so you can fix it.\n2. **The Promote to Active button.** Open a Draft part's detail panel; on the **Identity** tab, below the barcode block, a **Promote to Active** button appears (Draft parts only). Click it and the server runs the readiness checks. On success the part flips to Active. If a gate isn't satisfied, an inline panel lists exactly what's missing — fix those items (add a BOM line, set a cost, pick a stock UoM, etc.) and click Promote again.\n\n**The readiness gates** are the checks that must pass before a part can go Active. Which gates apply depends on the part's (procurement × inventory class) combination — the New Part workflow definition for each combo declares which steps are required. The common gates:\n\n- **Basics** — name + procurement source + inventory class present. (Always satisfied once the part exists, because the fork dialog collects the axes before creation.)\n- **BOM** — at least one BOM line. Required for assemblies (Make/Subassembly, Phantom, Subcontract+Subassembly). Skipped for single-piece fab and simple buy parts.\n- **Routing** — at least one manufacturing operation. Required for Make-axis parts. Skipped for Buy/Subcontract/Phantom (no in-house operations).\n- **Cost** — a manual cost override OR a calculated cost snapshot. Required for most stocked combos; skipped for tools (cost flows through the asset) and phantoms (never stocked).\n- **Sourcing** — a preferred vendor selected. Required for Buy and Subcontract parts; optional for Make/Phantom.\n- **Inventory** — a stock unit of measure set. Required for every non-Phantom combo. (Usually pre-filled to 'ea' on creation, so it's satisfied by default.)\n\nObsolete is a manual status move (Identity cluster Status field) — there's no gate, because retiring a part is always allowed. Prototype is for parts you want usable in jobs/inventory while still flagged as not finalized; you can set it directly on the Status field too.\n\n### The Detail Page\n\nThe Part detail page is a multi-tab cluster system. Tabs are not fixed — they're resolved per (procurement, inventory class) combination by the layout resolver. Common tabs:\n\n- **Identity** — always first. Part number, axes (read-only), name, revision, description, status. Edit name/description/revision/status inline; axes are immutable.\n- **Inventory** — min stock, reorder point, reorder quantity, safety stock, traceability, ABC class. Hidden for non-stocked combinations.\n- **MRP** — planning policy: lot sizing rule, fixed/min order qty, multiples, planning + demand fences. Hidden when the part isn't MRP-planned.\n- **Cost** — manual cost override, current cost calculation snapshot id, valuation class, landed-cost breakdown. Hidden for Phantom combos.\n- **Pricing** — list prices, effective dates, history.\n- **Material** — material spec, weight/dimensions/volume (canonical SI columns + display unit so the user types in their preferred unit).\n- **UoM** — stock / purchase / sales units of measure. Lookup-driven dropdowns.\n- **Quality** — receiving inspection toggle, template, frequency, skip-after-N count.\n- **Routing** — manufacturing operations (Make and Phantom combos).\n- **BOM** — bill of materials (Make / Subassembly / Phantom). Table or tree view.\n- **Sources** — vendor sources (Buy / Subcontract / dual-sourced parts). One row per (vendor, part) intersection.\n- **Alternates** — substitute parts.\n- **Purchase History** — most recent POs that included this part.\n- **3D Viewer** — appears only when an STL file is attached.\n- **Activity** — chronological log of every definitional change.\n- **Files** — always last. CAD, drawings, datasheets.\n\nEach editable cluster has its own Save / Cancel pair (lower-right of the cluster). You can edit Identity without touching Inventory; saves are scoped per cluster. The page never has a single global Save.\n\n### Vendor Sources (Sources Tab)\n\nFor parts that are bought (or that have Buy options on a Make-axis part), the **Sources** tab lists the (Vendor, Part) intersections — one row per vendor that supplies this part. Each source captures vendor-scoped sourcing data:\n\n- Vendor's part number\n- Vendor's manufacturer part number (distributor case)\n- Per-vendor lead time, MOQ, pack size\n- Country of origin, HTS code\n- AVL approval flag, certifications, last-quoted date\n- **Preferred** flag — at most one preferred vendor per part. Mirrors to the Part's PreferredVendorId.\n- **Tiered pricing** — quantity breaks (min qty ≤ requested qty wins), with effective-from and effective-to dates.\n\nAdding a source is a normal create; the price tier list is managed inline. Setting a new preferred source automatically un-preferreds the previous one.\n\n### Bill of Materials (BOM)\n\nFor Make and Phantom assemblies, the BOM tab lists every component:\n\n- **Child Part** — entity-picker search. Cannot be the parent itself.\n- **Quantity** — per parent unit.\n- **Source Type** — Make (manufactured in-house, may trigger sub-job), Buy (purchased), Stock (pulled from inventory).\n- **Reference Designator** — engineering reference (R1, C4, J2 for electronics).\n- **Lead Time Days** — days to obtain this specific component.\n- **Notes** — free-form.\n\nBOM lines can be viewed as a flat sortable table or a hierarchical tree. The **Used In** view (reverse BOM) is reachable via the Alternates / Sources cross-reference and shows parent assemblies that consume this part.\n\n**Revision history.** The BOM tab also carries a read-only **revision history** panel. Every time you change the component list — add, edit, or remove a line — the server automatically freezes a new revision and stamps it with an effective date. The history panel lists those revisions newest-first, marks the current one, and shows how many lines each contained. Expand any revision to see its frozen component snapshot exactly as the BOM stood at that moment (part numbers, quantities, source types, reference designators, notes). You don't create revisions by hand — editing the BOM creates them for you. This is the audit trail for \"what was this assembly made of, and when did it change?\" — important for traceability and for understanding why an older job's cost or material list differs from today's.\n\n### Routing (Operations)\n\nMake-axis parts have a Routing tab listing manufacturing operations in sequence:\n\n- **Step Number**, **Title**, **Instructions**, **Work Center**, **Estimated Minutes**, **QC Checkpoint** (with QC Criteria), and **Referenced Operation** (cross-reference for dependencies).\n- Each operation can subcontract one step (an op-level IsSubcontract flag) — distinct from a wholly-subcontracted part.\n- BOM lines can be assigned to operations as **Operation Materials** so the routing knows which materials are consumed at each step.\n- Operations support per-operation file attachments and an activity log.\n\nThe routing renders in list mode (sequential cards) or flow mode (visual diagram).\n\n### How Parts Connect to Other Modules\n\n**Jobs** — when a job is created on the Kanban board, it can be linked to a part. The part's BOM drives material requirements, the routing defines the production steps.\n\n**Inventory** — parts are tracked in storage locations and bins. The Inventory cluster surfaces total quantity on hand and a low-stock warning when quantity drops below the min stock threshold.\n\n**Purchase Orders** — when a BOM line has source type Buy, the system knows the component needs procurement. The preferred vendor (from the Sources tab) drives PO creation.\n\n**Sales Orders & Quotes** — parts appear as line items with pricing from the part's price history (or vendor tier price for cost-plus margin).\n\n**Assets** — Tool-class parts can be linked to a tooling asset for shot count tracking and maintenance scheduling.\n\n**Barcode/QR** — every part can have a barcode label printed. Scanning a part's barcode on the Parts page populates the search field instantly.\n\n### Creating a Part\n\nNew Part starts with a 4-question fork dialog: procurement source, inventory class, an optional item kind tag, and the creation mode (express single-page form vs guided multi-step workflow, with the dialog recommending one per combo). Based on the answers, the system picks a workflow definition and routes you into a guided multi-step form (Basics → Inventory → Quality → Sourcing → Costing → … → Save). You can pause at any step; the partial state is preserved as a draft and shown as a ghost row on the parts list, resumable from where you left off.\n\nLightweight cases (Raw Material, Consumable) drop straight into a single-page express form instead of a multi-step workflow.\n\n### View Modes\n\nThe parts list page has two view modes: **Table View** (sortable, column-managed data table) and **Card Grid View** (visual cards). Toggle in the upper-right; preference is saved per user.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog — Guided Tour",
            Slug = "parts-walkthrough",
            Summary = "A guided tour of the parts list, axis filters, view toggle, the New Part fork, and a glance at the resolver-driven detail page (Identity / Inventory / Cost / Sources / BOM / Routing / Activity / Files).",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","walkthrough","sourcing"]""",
            ContentJson = """{"appRoute":"/parts","startButtonLabel":"Tour Parts Catalog","steps":[{"element":"[data-testid='new-part-btn']","popover":{"title":"New Part","description":"Click here to start a new part. You'll first answer a short fork: how the part is procured (Make, Buy, Subcontract, Phantom), which inventory bucket it belongs to (Raw, Component, Subassembly, FinishedGood, Consumable, Tool), an optional item kind tag, and the creation mode (express vs guided — it recommends one). Based on your answers, the system picks a workflow and walks you through the right cluster of fields.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Parts","description":"Search by part number, name, manufacturer, or external part number. Press Enter to apply. Barcode scanners feed into this field automatically — scan a label and the matching part is found.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(1)","popover":{"title":"Status Filter","description":"Filter by lifecycle status: Draft (work-in-progress), Prototype (in testing), Active (approved for use), or Obsolete (preserved for history but not for new orders). Pick 'All' to see everything.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(2)","popover":{"title":"Procurement Source Filter","description":"Filter by procurement axis: Make (in-house), Buy (purchased), Subcontract (vendor builds it whole), or Phantom (logical assembly that never physically exists). Combine with the Inventory Class filter to narrow further.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(3)","popover":{"title":"Inventory Class Filter","description":"Filter by inventory bucket: Raw, Component, Subassembly, FinishedGood, Consumable, or Tool. This axis decides which inventory rules apply (stocking, traceability, ABC class).","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table View (sortable data table with column management) and Card Grid View (visual cards). Your preference is saved across sessions.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Parts Data Table","description":"Click any row to open the part detail panel. Columns include Part #, Name, Procurement, Class, Status, BOM count, Effective Price, and a Completeness chip. Click headers to sort. Use the gear icon to show/hide columns or rearrange them. Draft rows from in-progress workflow runs appear as 'ghost' rows pinned to the top — click to resume, or click the X to abandon the draft.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Field Reference",
            Slug = "parts-field-reference",
            Summary = "Complete reference for every field, axis, status, validation rule, table column, and detail-page cluster in the Parts Catalog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","reference","sourcing"]""",
            ContentJson = """{"title":"Parts Catalog Field Reference","groups":[{"heading":"Identity Axes (chosen on the New Part fork)","items":[{"label":"Procurement Source (required)","value":"Make / Buy / Subcontract / Phantom. Determines workflow path on creation, which detail-page tabs render, and which gates fire at promotion. Immutable after creation. data-testid: part-procurement-source"},{"label":"Inventory Class (required)","value":"Raw / Component / Subassembly / FinishedGood / Consumable / Tool. Determines which inventory rules apply (stocking, traceability, ABC). Immutable after creation. data-testid: part-inventory-class"},{"label":"Item Kind (optional)","value":"Admin-configurable taxonomy from reference_data group 'part.item_kind' (Fastener, Electronic, Packaging, Hardware, Material, etc.). Descriptive only — does not gate any logic."}]},{"heading":"Identity Cluster Fields","items":[{"label":"Part Number","value":"System-generated on creation. Read-only. Format = categorical prefix (PRT, ASM, RAW, CON, TLG, FST, ELC, PKG) + 5-digit zero-padded sequence. Cannot be changed."},{"label":"Name (required)","value":"Short canonical identifier (e.g., 'Sheath Mudkipper'). Max 256 characters. data-testid: part-identity-name / part-name"},{"label":"Description","value":"Long-form notes. Optional. Max 2000 characters. data-testid: part-identity-description / part-description"},{"label":"Revision","value":"Engineering rev letter. Default 'A'. Max 5 characters. Increment on design change (A → B → C). data-testid: part-identity-revision / part-revision"},{"label":"Status (required)","value":"Draft / Prototype / Active / Obsolete. Edit inline via the Identity cluster's Status select. data-testid: part-identity-status"}]},{"heading":"Tier 0 Identity Fields","items":[{"label":"Traceability","value":"None (bulk, no tracking) / Lot (by batch) / Serial (per unit). Required. Replaces the old isSerialTracked boolean."},{"label":"ABC Class","value":"A (high value, tight control) / B (moderate) / C (low value, loose control) / Unset. Drives cycle-count frequency and control rigor."},{"label":"Manufacturer","value":"OEM company name. Optional. Distinct from a distributor's vendor name."},{"label":"Manufacturer Part Number","value":"OEM's part number. Optional. Distinct from a distributor's vendor part number — both can coexist on a VendorPart row."}]},{"heading":"Inventory Cluster Fields","items":[{"label":"Min Stock","value":"Minimum quantity to keep on hand. When inventory drops below this, a low-stock warning appears. Optional. Must be >= 0."},{"label":"Reorder Point","value":"Quantity level at which a reorder should be triggered. Used by MRP. Optional. Must be >= 0."},{"label":"Reorder Quantity","value":"How many units to order when reordering. Optional."},{"label":"Safety Stock (days)","value":"Buffer days of stock to maintain beyond the calculated reorder point. Optional."},{"label":"Traceability","value":"None / Lot / Serial. See Tier 0 Identity."},{"label":"ABC Class","value":"A / B / C / Unset. See Tier 0 Identity."}]},{"heading":"Cost Cluster Fields","items":[{"label":"Manual Cost Override","value":"Currency input. When set, overrides the calculated landed cost. Currency-formatted with the company default currency. Clear via the input's clear button (negative or empty saves null)."},{"label":"Cost Calculation Id","value":"Read-only. The current cost-calculation snapshot id. Background job recomputes on BOM / vendor / price changes."},{"label":"Valuation Class","value":"Read-only label. Pillar 2 valuation grouping (admin-configurable in reference_data)."},{"label":"Landed Cost Surface","value":"Read-only breakdown of unit cost + freight + duty + tariffs. Sourced from VendorPartPriceTier and shipment cost allocation."}]},{"heading":"Promote to Active & Readiness Gates","items":[{"label":"Promote to Active (button)","value":"Identity tab of a Draft part's detail panel, below the barcode block. Only renders when status = Draft. Runs the readiness gates server-side; on success flips Draft → Active. data-testid: promote-to-active-btn"},{"label":"Promote hint","value":"'Runs readiness checks. Tells you what's missing if anything blocks promotion.' Promotion never silently fails — you always learn why."},{"label":"Missing-data panel","value":"If a gate isn't satisfied, an inline 'Cannot promote — missing data' panel lists each unmet gate's message. Fix the items and click Promote again. Dismiss with the X. data-testid: promote-missing"},{"label":"Workflow Complete (alternate path)","value":"Clicking Complete on the last step of the New Part workflow runs the same gates and auto-promotes to Active when they pass. If blocked, the message names the step to finish first."},{"label":"Gate: Basics","value":"Name + procurementSource + inventoryClass present. Always satisfied once the part exists (the fork dialog collects the axes pre-creation)."},{"label":"Gate: BOM (hasBom)","value":"At least one BOM line. Required for Make/Subassembly, Phantom, and Subcontract+Subassembly. Message: 'BOM not yet defined.'"},{"label":"Gate: Routing (hasRouting)","value":"At least one manufacturing operation. Required for Make-axis parts. Message: 'Routing operations not yet defined.'"},{"label":"Gate: Cost (hasCost)","value":"manualCostOverride OR a currentCostCalculationId present. Required for most stocked combos; skipped for tools and phantoms. Message: 'Cost not yet set.'"},{"label":"Gate: Sourcing (hasSourcing)","value":"preferredVendorId set. Required for Buy and Subcontract parts; optional for Make/Phantom. Message: 'Preferred vendor not yet selected.'"},{"label":"Gate: Inventory (hasInventory)","value":"stockUomId set. Required for every non-Phantom combo; usually pre-filled to 'ea' so satisfied by default. Message: 'Stock unit of measure not yet set.'"},{"label":"Which gates apply","value":"Determined by the part's (procurement × inventory class) combo — each New Part workflow definition declares which steps (and thus gates) are required. A Buy+Consumable part has far fewer gates than a Make+FinishedGood."},{"label":"Obsolete / Prototype moves","value":"Set directly on the Identity cluster Status field — no readiness gate. Only Draft → Active is gated."}]},{"heading":"Sources Tab (VendorPart Intersection)","items":[{"label":"Add Vendor Source","value":"Open dialog to add a (Vendor, Part) row. Required: Vendor (entity picker)."},{"label":"Vendor Part Number","value":"Vendor's catalog number for this part."},{"label":"Vendor MPN","value":"Vendor's manufacturer part number — for the case where the vendor is a distributor and the part has a different OEM identity."},{"label":"Lead Time (days)","value":"Per-vendor lead time. Overrides the part-level default for this source."},{"label":"MOQ","value":"Minimum order quantity for this vendor."},{"label":"Pack Size","value":"Vendor packs in multiples of this number."},{"label":"Country of Origin","value":"For HTS/customs purposes."},{"label":"HTS Code","value":"Harmonized Tariff Schedule code. Used by import duty calculations."},{"label":"AVL Approved","value":"Toggle. Whether this source is on the Approved Vendor List."},{"label":"Certifications","value":"Free-text. Quality certifications (ISO 9001, AS9100, RoHS, etc.)."},{"label":"Last Quoted At","value":"Date the vendor last quoted on this part. Stale-source detection."},{"label":"Preferred","value":"Toggle. At most one preferred source per part — flipping this on auto-flips off the previous preferred. Mirrors to Part.PreferredVendorId."},{"label":"Price Tiers","value":"Quantity-break rows: min qty + unit price + currency + effective-from + effective-to. Inline add / edit / remove."}]},{"heading":"BOM Cluster (Make / Subassembly / Phantom)","items":[{"label":"Child Part (required)","value":"Entity picker searching parts. Cannot be the parent itself."},{"label":"Quantity (required)","value":"How many child parts per parent unit. Must be > 0. Default 1."},{"label":"Source Type","value":"Make (in-house, may trigger sub-job) / Buy (purchased) / Stock (from inventory). Default Buy."},{"label":"Reference Designator","value":"Engineering reference (R1, C4, J2)."},{"label":"Lead Time Days","value":"Days to obtain this specific component. Displayed as 'Xd' in the BOM table."},{"label":"Notes","value":"Free-form."}]},{"heading":"Alternates Tab (Substitute Parts)","items":[{"label":"Add Alternate (button)","value":"Opens the Add Alternate Part dialog. The alternate-part picker can inline-create a not-yet-cataloged part (defaults its procurement to Buy)."},{"label":"Alternate Part (required)","value":"Entity picker searching parts. The part this one can be substituted with."},{"label":"Type","value":"Substitute (info chip) / Equivalent (success chip) / Superseded (warning chip). Describes the relationship."},{"label":"Priority (required)","value":"Integer >= 1. Lower = preferred substitute. Drives which alternate the system suggests first."},{"label":"Conversion Factor","value":"Optional. Quantity ratio when the alternate isn't 1:1 (e.g., 1.2 = need 1.2 of the alternate per 1 of the original)."},{"label":"Approved (toggle)","value":"Whether the alternate is approved for production use. Unapproved rows show an inline Approve button in the table; click it to approve in place."},{"label":"Bidirectional (toggle)","value":"ON = the substitution works both ways (each part is an alternate of the other). OFF = one-way only. Table shows swap_horiz vs arrow_forward to indicate direction. Default ON."},{"label":"Notes","value":"Free-form."},{"label":"Approve (row action)","value":"For an unapproved alternate, an Approve button appears in the Approved column; clicking it sets isApproved without reopening the dialog."},{"label":"Remove (row action)","value":"Trash icon — confirms, then removes the alternate relationship."}]},{"heading":"Serials Tab (Serial-Tracked Parts)","items":[{"label":"When it appears","value":"The Serials tab only renders when the part's Traceability = Serial. Bulk/Lot-tracked parts don't have it."},{"label":"New Serial (button)","value":"Opens the Create Serial Number dialog. data-testid: serial-save-btn"},{"label":"Serial Number (required)","value":"The unique serial value. Max 100 characters. data-testid: serial-value"},{"label":"Notes","value":"Optional. data-testid: serial-notes"},{"label":"Status filter","value":"Filter the list by status: All / Available / In Use / Shipped / Returned / Scrapped / Quarantined."},{"label":"List columns","value":"Serial #, Status (color chip), Location, Job, Manufactured date, Children count."},{"label":"Row click → detail","value":"Opens the serial detail dialog: part, job, current location, customer, parent serial, manufactured/shipped dates, notes."},{"label":"History (in detail)","value":"Chronological movement/lifecycle log for that serial — action, from/to location, timestamp, details."},{"label":"Genealogy (button in detail)","value":"Opens a tree view (account_tree icon) showing the parent/child serial hierarchy — which serialized sub-assemblies went into this unit, traced down through the build."},{"label":"Status values","value":"Available (green) / InUse (primary) / Shipped (info) / Returned (warning) / Scrapped (error) / Quarantined (muted)."}]},{"heading":"BOM Revision History (read-only)","items":[{"label":"What it is","value":"A read-only panel on the BOM tab listing every frozen revision of the component list, newest first."},{"label":"How revisions are created","value":"Automatically — every BOM line add/edit/remove freezes a new revision server-side. You never create one by hand."},{"label":"Row contents","value":"Revision number (v1, v2…), a 'current' marker on the active one, effective date, line count, and any notes."},{"label":"Expand a revision","value":"Click a row to load and show its frozen snapshot: each line's part #, description, quantity + UoM, source type, reference designator, notes."},{"label":"Purpose","value":"Audit trail for 'what was this assembly made of, and when did it change?' — explains why an older job's material list or cost differs from today's."}]},{"heading":"Routing Cluster (Make Only)","items":[{"label":"Step Number","value":"Sequence (1, 2, 3...). Auto-populated for new ops with the next available number."},{"label":"Title (required)","value":"Short op name (e.g., 'CNC Rough Cut', 'Deburr', 'Heat Treat'). Max 200 characters."},{"label":"Instructions","value":"Detailed multi-line work instructions for the operator."},{"label":"Work Center","value":"Entity picker (work centers). Optional."},{"label":"Estimated Minutes","value":"Expected duration. Optional. Must be >= 1 if provided."},{"label":"Is Subcontract (toggle)","value":"When ON, this single operation is sent out to a subcontracter. Distinct from procurementSource = Subcontract on the part level (which means the entire part is outsourced)."},{"label":"QC Checkpoint (toggle)","value":"When ON, requires inspection before next step proceeds."},{"label":"QC Criteria","value":"Textarea, shown when QC Checkpoint is on."},{"label":"Operation Materials","value":"BOM lines assigned to this op. Each row = (BOM line, quantity consumed at this step)."}]},{"heading":"Quality Cluster","items":[{"label":"Requires Receiving Inspection (toggle)","value":"When ON, every receipt of this part triggers a QC inspection."},{"label":"Receiving Inspection Template","value":"FK to QcTemplate. Determines the inspection checklist."},{"label":"Inspection Frequency","value":"Always / Sample / Skip-after-N. Drives the inspection skip logic."},{"label":"Inspection Skip After N","value":"After N successful inspections in a row, subsequent receipts skip inspection until a defect is found."}]},{"heading":"Material Cluster","items":[{"label":"Material Spec","value":"FK to material specification (reference_data group 'material.spec'). 6061-T6 Aluminum, 304 Stainless, ABS Plastic, etc."},{"label":"Weight (canonical g) + Display Unit","value":"Weight stored in grams. Display unit is what the user typed (g, kg, oz, lb). Round-trip preserves the entry unit."},{"label":"Length / Width / Height (canonical mm) + Display Unit","value":"Dimensions in mm. Display unit (mm, cm, m, in, ft) preserved."},{"label":"Volume (canonical mL) + Display Unit","value":"Volume in milliliters. Display unit (mL, L, oz, gal) preserved."},{"label":"Valuation Class","value":"FK to reference_data group 'valuation.class'. Pillar 2 inventory valuation grouping."}]},{"heading":"UoM Cluster","items":[{"label":"Stock UoM","value":"Unit the part is stocked in (the canonical inventory unit). FK to reference_data."},{"label":"Purchase UoM","value":"Unit the part is purchased in. May differ from stock UoM (e.g., stock by piece, purchase by case)."},{"label":"Sales UoM","value":"Unit the part is sold in."}]},{"heading":"MRP Cluster","items":[{"label":"Is MRP Planned (toggle)","value":"Whether MRP includes this part in its planning runs."},{"label":"Lot Sizing Rule","value":"FixedOrderQty / LotForLot / EconomicOrderQty / FixedPeriod. Drives how MRP groups demand into orders."},{"label":"Fixed Order Quantity","value":"For FixedOrderQty rule. Always order this much."},{"label":"Minimum Order Quantity","value":"Floor for any single order."},{"label":"Order Multiple","value":"Order in multiples of this number."},{"label":"Planning Fence (days)","value":"Inside this fence, MRP doesn't auto-generate new orders — manual control only."},{"label":"Demand Fence (days)","value":"Inside this fence, demand changes are not allowed without override."}]},{"heading":"Pricing Cluster","items":[{"label":"Set New Price","value":"Currency input. Saving creates a new price row and marks the previous as historical."},{"label":"Effective From","value":"Date the new price takes effect. Defaults to today."},{"label":"Notes","value":"Optional. Reason for the price change."},{"label":"Price History","value":"Past prices: price, effective-from, effective-to (or '---' if current)."}]},{"heading":"Detail Page Tab Layout","items":[{"label":"Resolver-driven","value":"Tabs are NOT fixed — they're computed from (procurementSource, inventoryClass) by PartDetailLayoutResolverService. Identity always first, Files always last. Activity is a persistent footer below the tab body, not a tab."},{"label":"Common tabs","value":"Identity, Inventory, MRP, Cost, Pricing, Material, UoM, Quality, Routing, BOM, Sources, Alternates, Purchase History, 3D Viewer, Activity, Files."},{"label":"URL sync","value":"Active tab is bound to ?tab=<id> so refresh and shared links land on the right tab."},{"label":"Per-cluster save","value":"Each editable cluster has its own Save / Cancel pair (lower-right). No global page-level Save. Saves are scoped — edit Identity without affecting Inventory."}]},{"heading":"Parts List Table Columns","items":[{"label":"Part # (partNumber)","value":"System-generated. Sortable. Bold monospace. 120px."},{"label":"Name","value":"Part name. Sortable. Flexible width. Includes a completeness badge."},{"label":"Procurement (procurementSource)","value":"Make / Buy / Subcontract / Phantom chip. Sortable."},{"label":"Class (inventoryClass)","value":"Raw / Component / Subassembly / FinishedGood / Consumable / Tool chip. Sortable."},{"label":"Status","value":"Color-coded badge: Active=green, Draft=gray, Prototype=blue, Obsolete=red. Sortable + filterable."},{"label":"BOM Count","value":"Number of direct BOM lines. Center-aligned. 60px."},{"label":"Effective Price","value":"Current list price (or '---' if no price configured)."},{"label":"Completeness","value":"Chip showing how complete the part record is (Identity → Sourcing → Pricing → Quality coverage)."}]},{"heading":"Validation Rules","items":[{"label":"Procurement Source / Inventory Class","value":"Required on creation. Cannot be changed afterward."},{"label":"Name","value":"Required. Max 256 characters."},{"label":"Description","value":"Optional. Max 2000 characters."},{"label":"Revision","value":"Optional. Max 5 characters. Defaults to 'A'."},{"label":"Traceability","value":"Required. None / Lot / Serial."},{"label":"Min Stock / Reorder Point / Safety Stock","value":"Optional. Must be >= 0."},{"label":"BOM Quantity","value":"Required. Must be > 0."},{"label":"Operation Step Number","value":"Required. Must be >= 1."},{"label":"Operation Title","value":"Required. Max 200 characters."},{"label":"VendorPart preferred uniqueness","value":"Server-side: at most one VendorPart per part with isPreferred=true. Setting it true on one row clears it on every other."},{"label":"Submit button + validation popover","value":"All forms use the <app-validation-button> stereotype: when invalid, a small warning-triangle icon appears next to a disabled Save. Click the icon to see the list of violations."}]},{"heading":"Buttons and Actions","items":[{"label":"New Part (page header)","value":"Opens the 4-question fork dialog. data-testid: new-part-btn"},{"label":"Resume Draft (parts list)","value":"Click a 'ghost' draft row (a workflow run that hasn't materialized a Part yet) to resume the workflow where you left off."},{"label":"Abandon Draft","value":"X button on a ghost draft row. Discards the in-progress run."},{"label":"Edit (cluster header)","value":"Each editable cluster has an inline Edit button. Click to enter edit mode for that cluster only."},{"label":"Save / Cancel (cluster footer)","value":"Per-cluster. Save commits this cluster's changes. Cancel reverts in-progress edits and exits edit mode."},{"label":"Status change","value":"Identity cluster Status select — Draft / Prototype / Active / Obsolete. Use it for Prototype and Obsolete moves. Draft → Active goes through the readiness-gated Promote to Active button instead."},{"label":"Promote to Active (Identity tab, Draft only)","value":"Runs readiness gates; promotes Draft → Active when they pass, or lists what's missing. data-testid: promote-to-active-btn"},{"label":"Add Alternate (Alternates tab)","value":"Opens the Add Alternate Part dialog."},{"label":"Approve Alternate (row action)","value":"Inline Approve button on an unapproved alternate row."},{"label":"New Serial (Serials tab)","value":"Opens the Create Serial Number dialog (Serial-tracked parts only)."},{"label":"View Genealogy (serial detail)","value":"Opens the parent/child serial tree for the selected serial."},{"label":"Add Vendor Source (Sources tab)","value":"Opens the VendorPart create dialog."},{"label":"Add Price Tier","value":"Inline action on a vendor source — adds a quantity-break row."},{"label":"Add BOM Line","value":"Opens the BOM line creation dialog with entity picker for child part."},{"label":"Add Operation","value":"Opens the operation creation dialog with auto-incremented step number."},{"label":"View Mode Toggle (page level)","value":"Switch between Table View and Card Grid View."},{"label":"Row click (parts table)","value":"Opens the part detail panel."}]},{"heading":"Activity Logging","items":[{"label":"Created","value":"On part create — one ActivityLog row anchored to the part with action 'created' and a description naming the part number, name, procurement, and inventory class."},{"label":"Updated","value":"Per save (rollup rule) — one row per request, with description summarizing all changed fields."},{"label":"Deleted","value":"On soft-delete — one row anchored to the part with action 'deleted'."},{"label":"VendorPart mutations","value":"Indexing-points rule — VendorPart create / update / delete / price-tier add / price-tier remove each emit two activity rows: one anchored to the Part, one to the Vendor."}]},{"heading":"Barcode Scanner Integration","items":[{"label":"Scanner context","value":"The Parts page sets the global scanner context to 'parts'. Scans on this page populate the search filter."},{"label":"Scan behavior","value":"Scanned value is dropped into the search input and the parts list reloads with that value as the search term — finds the part by its barcode-encoded part number."},{"label":"Supported scanners","value":"USB barcode scanners (keyboard wedge mode) and NFC readers (ACR122U with NTAG215 tags). Scanner must be in keyboard emulation mode."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Knowledge Check",
            Slug = "parts-quiz",
            Summary = "Test your knowledge: the three classification axes, identity immutability, BOM source types, vendor sources, routing, traceability, and the per-cluster save model.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","quiz","sourcing"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pt1","text":"A part is built from multiple sub-components in your shop. Which Procurement Source / Inventory Class combination fits?","options":[{"id":"a","text":"Buy / Component"},{"id":"b","text":"Make / Subassembly","isCorrect":true},{"id":"c","text":"Subcontract / FinishedGood"},{"id":"d","text":"Phantom / Raw"}],"explanation":"Make + Subassembly: 'Make' because you produce it in-house, 'Subassembly' because it's an assembly that's itself a component of something larger. The BOM tab will appear on the detail page; the Routing tab will appear because Make-axis parts have manufacturing operations."},{"id":"pt2","text":"What's the difference between a part with procurementSource = Subcontract and an operation with isSubcontract = true?","options":[{"id":"a","text":"They mean the same thing — both indicate vendor outsourcing"},{"id":"b","text":"Subcontract on the part = the entire part is built by a vendor; isSubcontract on an operation = ONE step is sent out, but the rest of the part is made in-house","isCorrect":true},{"id":"c","text":"Subcontract on the part is the legacy form; only operation-level subcontracting is supported now"},{"id":"d","text":"isSubcontract on an operation triggers an automatic PO; Subcontract on a part doesn't"}],"explanation":"They model two different scopes. Procurement Source = Subcontract means the whole part is outsourced — the vendor delivers it complete. An operation-level isSubcontract flag on a Make-axis part means one step in the routing is sent out (e.g., we machine the housing in-house but send it out for anodizing)."},{"id":"pt3","text":"Why are Procurement Source and Inventory Class immutable after a part is created?","options":[{"id":"a","text":"They aren't — there's an Edit button on the Identity cluster that lets you change them"},{"id":"b","text":"They drive which detail tabs appear, which validators run, which workflows fire on creation, and which gates fire at promotion. Changing them mid-life would invalidate every downstream reference and history record","isCorrect":true},{"id":"c","text":"It's a database constraint with no business reason"},{"id":"d","text":"Only the procurement axis is immutable; inventory class can be changed freely"}],"explanation":"Both axes are baked into every cost calculation, every BOM that uses this part, every vendor source, and the part's own activity history. Reclassifying mid-life would silently invalidate all of that. If a part truly needs to be reclassified, use a dedicated migration tool that re-runs the workflow and writes a new audit row — not an inline edit."},{"id":"pt4","text":"What does Traceability = Lot mean for a part?","options":[{"id":"a","text":"The part is tracked by individual serial numbers, one per unit"},{"id":"b","text":"The part is tracked by batch — receipts, moves, and consumption are recorded against the lot, not against individual units","isCorrect":true},{"id":"c","text":"The part can only be sold by the lot, never split"},{"id":"d","text":"The part is exempt from inventory tracking entirely"}],"explanation":"Lot traceability means the smallest tracked unit is the batch (lot). Receipts create a LotRecord; moves and consumption reference the lot id. Use Lot for materials and chemicals where individual units aren't distinguishable. Use Serial for high-value or regulated items where every unit needs its own identity. Use None for bulk consumables where neither matters."},{"id":"pt5","text":"You're editing a part. You change the Name in the Identity cluster, then click Save. What happens?","options":[{"id":"a","text":"The whole part is saved — Identity, Inventory, Cost, and every other cluster"},{"id":"b","text":"Only the Identity cluster's fields are sent to the server. Other clusters' data isn't touched","isCorrect":true},{"id":"c","text":"Nothing — there's no per-cluster save; the page has a global Save button"},{"id":"d","text":"The save fails because the Inventory cluster is also dirty"}],"explanation":"The detail page has per-cluster save / cancel pairs (lower-right of each cluster). Each Save sends only that cluster's fields. This means you can edit Identity safely without touching Inventory, and vice versa — there's no risk of accidentally saving stale values from another cluster."},{"id":"pt6","text":"You add a vendor source to a part and toggle 'Preferred' on. Another vendor source on the same part was previously preferred. What happens?","options":[{"id":"a","text":"The save is rejected — there can only be one preferred per part, you must un-prefer the other one first"},{"id":"b","text":"Both rows end up preferred — the constraint is advisory","isCorrect":false},{"id":"c","text":"The previous preferred is automatically un-preferred — the server enforces at most one preferred per part. Part.PreferredVendorId is updated to point at the new preferred row","isCorrect":true},{"id":"d","text":"Only the database constraint catches it on the next read; the save itself is silent"}],"explanation":"The preferred-uniqueness invariant is enforced server-side: setting isPreferred=true on one VendorPart row automatically unsets it on every other VendorPart for the same part within the same SaveChanges. The Part.PreferredVendorId column is a denormalized mirror that points at the preferred row for fast access — it's kept in sync as part of the same operation."},{"id":"pt7","text":"You add a price tier to a vendor source: minQuantity=100, unitPrice=$1.50, effectiveFrom=2026-04-01. The same vendor already has minQuantity=10, unitPrice=$2.00 (current). A buyer asks for 250 units. Which tier applies?","options":[{"id":"a","text":"$2.00 because that tier was created first"},{"id":"b","text":"$1.50 because the requested quantity (250) is at or above 100, and 100 is the highest minQuantity that still fits","isCorrect":true},{"id":"c","text":"$2.00 because tiers don't apply to vendor-quoted prices"},{"id":"d","text":"The system averages the tiers"}],"explanation":"Quantity-break rule: of the active tiers (effectiveFrom <= today, effectiveTo null or > today), pick the one whose minQuantity is the highest value that's still <= the requested quantity. 250 >= 100, so the $1.50 tier wins. If the buyer asked for 50 units instead, only the minQ=10 tier would qualify and $2.00 would apply."},{"id":"pt8","text":"What's the role of the BOM source type 'Make' on a BOM line?","options":[{"id":"a","text":"It marks the entry as obsolete"},{"id":"b","text":"It tells the system the component is manufactured in-house, which can trigger a sub-job during production planning","isCorrect":true},{"id":"c","text":"It locks the BOM line from being edited"},{"id":"d","text":"It hides the entry from the BOM tree view"}],"explanation":"Source Type = Make means the component is itself manufactured in-house. During production planning (BOM explosion), the system can create a sub-job to produce the Make component before the parent job needs it. Buy entries trigger purchase orders; Stock entries assume the component is on hand."},{"id":"pt9","text":"Which tabs does the Part detail page show, and how are they chosen?","options":[{"id":"a","text":"A fixed five-tab layout: Info, BOM, Used In, Routing, Files — same for every part"},{"id":"b","text":"A resolver-driven multi-tab layout — tabs are computed from (procurementSource, inventoryClass) by PartDetailLayoutResolverService. Identity is always first, Files always last (Activity is a persistent footer below the tab body, not a tab); intermediate tabs vary by axes","isCorrect":true},{"id":"c","text":"Whatever tabs were last visible — preference is per-user"},{"id":"d","text":"Only Identity — every other cluster opens in a separate dialog"}],"explanation":"The detail page uses PartDetailLayoutResolverService to map axes → ordered tab list. A Make + FinishedGood part might show Identity, Inventory, MRP, Cost, Pricing, Material, UoM, Quality, Routing, BOM, Sources, Alternates, Purchase History, Activity, Files. A Buy + Consumable part might show only Identity, Inventory, Cost, Pricing, Sources, Activity, Files. The 3D Viewer tab appears only when an STL file is attached."},{"id":"pt10","text":"You delete a part. What happens to the activity log for that part?","options":[{"id":"a","text":"It's deleted along with the part"},{"id":"b","text":"It's preserved — the part is soft-deleted (DeletedAt is stamped, the row stays). A 'deleted' activity row is appended","isCorrect":true},{"id":"c","text":"It's archived to a separate table"},{"id":"d","text":"It's deleted unless an admin opts in to keep it"}],"explanation":"Deletes are soft — DeletedAt + DeletedBy stamped, global query filter hides the row from normal reads, but it's still on disk. The DeletePart handler also writes a 'deleted' activity row anchored to the part, so an undelete-and-inspect flow can see exactly what happened. The same applies to every BaseEntity in the system."},{"id":"pt11","text":"Where does the New Part flow start?","options":[{"id":"a","text":"A long single-page form with every field at once"},{"id":"b","text":"A 4-question fork dialog (procurement, inventory class, optional item kind, and creation mode — express vs guided) that picks a workflow, then routes you into a guided multi-step form. Lightweight cases skip the workflow and use a single-page express form","isCorrect":true},{"id":"c","text":"You manually pick a workflow from a dropdown before any field"},{"id":"d","text":"There's no fork — every new part uses the same workflow"}],"explanation":"New Part starts with the fork dialog. Based on your answers, the system picks the right workflow definition (different combos use different step layouts) and routes you into it. You can pause anywhere — the partial state is saved as a draft and shown as a 'ghost' row on the parts list, resumable. Raw / Consumable cases drop directly into a one-page express form because they don't need the multi-step guidance."},{"id":"pt12","text":"Which tab on the Part detail page shows the (Vendor, Part) intersection rows — vendor's part number, lead time, MOQ, AVL approval, and tiered pricing?","options":[{"id":"a","text":"BOM"},{"id":"b","text":"Sources","isCorrect":true},{"id":"c","text":"Cost"},{"id":"d","text":"Material"}],"explanation":"The Sources tab lists VendorPart rows — one per vendor that supplies this part. It shows vendor part number, vendor MPN, per-vendor lead time, MOQ, pack size, country of origin, HTS code, AVL flag, certifications, last-quoted date, preferred flag, and the tiered pricing rows. The BOM tab shows the parts that go INTO this part; the Sources tab shows where this part comes FROM."},{"id":"pt13","text":"A Tool-class part (procurementSource = Buy, inventoryClass = Tool) is purchased and used to manufacture other parts. What special integration does it support?","options":[{"id":"a","text":"It can be linked to a tooling Asset for shot-count tracking and maintenance scheduling","isCorrect":true},{"id":"b","text":"It's automatically assigned to the Maintenance kanban board"},{"id":"c","text":"It bypasses inventory tracking entirely"},{"id":"d","text":"It can only be sold, not purchased"}],"explanation":"Tool-class parts can be linked to a tooling Asset (Asset.Type = Tooling) via the ToolingAssetId FK. The asset tracks current shot count, tool life expectancy, owner (in-house vs customer-owned), and maintenance schedule. This gives full traceability from the part record back to the physical tool that produces it."},{"id":"pt14","text":"How does the activity log handle a multi-field part update?","options":[{"id":"a","text":"One activity row per changed field"},{"id":"b","text":"One activity row per request, with a description summarizing all changed fields ('Updated 4 fields: name, description, revision, status')","isCorrect":true},{"id":"c","text":"No activity row — only created/deleted are logged"},{"id":"d","text":"Two activity rows: one for the user action, one for each field"}],"explanation":"Rollup rule: one activity row per request, regardless of how many fields the user changed. The Description summarizes the count and the field names. This keeps the activity tab readable — per-field history (with old/new values) is the History tab's job, a different concept and a different table."},{"id":"pt15","text":"You scan a barcode on the Parts page. What happens?","options":[{"id":"a","text":"A new part is created with the scanned value as the part number"},{"id":"b","text":"The scanned value is placed into the search field and the parts list reloads to find the matching part","isCorrect":true},{"id":"c","text":"The scanned part's detail panel opens immediately"},{"id":"d","text":"Nothing — barcode scanning is only supported on Inventory"}],"explanation":"On the Parts page, the global scanner context is set to 'parts'. When a barcode is scanned, the value is dropped into the search input and the list reloads with that as the search term — finds the part by its barcode-encoded part number. From there, click the row to open the detail panel."},{"id":"pt16","text":"A part is sitting in Draft. You open its detail panel, go to the Identity tab, and click 'Promote to Active'. The part has a name and axes but no BOM line and it's a Make + Subassembly part. What happens?","options":[{"id":"a","text":"It promotes to Active immediately — Draft is just a label"},{"id":"b","text":"Promotion is blocked. The server runs the readiness gates, the BOM gate fails, and an inline 'Cannot promote — missing data' panel lists 'BOM not yet defined.' Add a BOM line, then click Promote again","isCorrect":true},{"id":"c","text":"The status select silently changes to Active but the part stays broken"},{"id":"d","text":"You must delete and recreate the part with a BOM"}],"explanation":"Draft → Active is readiness-gated. The Promote to Active button (Identity tab, Draft parts only) runs the gates server-side. For a Make + Subassembly part the BOM gate is required, so with no BOM line promotion is blocked and the missing-data panel names exactly what's wrong — promotion never fails silently. Fix the listed items and click Promote again. The New Part workflow's Complete button runs the same gates and auto-promotes when they pass."},{"id":"pt17","text":"Which readiness gate is required to promote a Make-axis part to Active, but does NOT apply to a Buy or Subcontract part?","options":[{"id":"a","text":"Routing (at least one manufacturing operation)","isCorrect":true},{"id":"b","text":"Sourcing (a preferred vendor selected)"},{"id":"c","text":"Inventory (a stock unit of measure set)"},{"id":"d","text":"Basics (name + axes present)"}],"explanation":"Routing requires at least one manufacturing operation and only applies to Make-axis parts — Buy and Subcontract parts have no in-house operations (the vendor owns the build), so the routing gate isn't part of their workflow definition. Conversely, Sourcing (preferred vendor) is required for Buy/Subcontract but optional for Make. Which gates apply is decided per (procurement × inventory class) combo by the New Part workflow definition."},{"id":"pt18","text":"On a serial-tracked part's Serials tab, you open a serial and click 'Genealogy'. What does it show?","options":[{"id":"a","text":"The list price history for the part"},{"id":"b","text":"A tree of the parent/child serial hierarchy — which serialized sub-assemblies were built into this unit, traced down through the build","isCorrect":true},{"id":"c","text":"Every other serial of the same part, sorted by status"},{"id":"d","text":"The BOM revision history"}],"explanation":"Genealogy opens a tree view (account_tree icon) of the serial's parent/child relationships — the as-built lineage showing which serialized components went into this unit. It's distinct from the serial's History panel (a chronological movement/lifecycle log) and from the part's BOM revision history (the definitional component list). The Serials tab itself only appears when the part's Traceability = Serial."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts — Advanced Reference",
            Slug = "parts-reference",
            Summary = "Edge-case reference: vendor Sources view modes + price-tier SCD-2 history, landed cost vs manual override, canonical material/UoM units, Purchase History & 3D Viewer tabs, serial genealogy, and per-combo workflow step differences.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","reference","advanced"]""",
            ContentJson = """{"body":"## Vendor Sources — View Modes & Price-Tier History\n\nThe **Sources** tab presents the same `VendorPart` list three ways via a view-mode toggle:\n\n- **Inspector** (default) — each source collapses to a header + summary + its tier table; the full per-source 1:1 fields (vendor MPN, lead time, MOQ, pack size, country of origin, HTS, certifications) render in a right-side property inspector for the selected card. Best for scan-then-drill.\n- **Compare** — sources stack as cards; a per-card chevron accordion-expands the full 1:1 fields inline for side-by-side reading.\n- **Pricing** — a flat cross-vendor table, one row per tier across every source, sorted by normalized **per-base-unit** cost (so the genuinely cheapest source reads first regardless of each vendor's pack size), then min qty, then vendor name. Answers \"where can I buy this at qty N cheapest?\".\n\n**Price tiers are SCD-2 (slowly-changing dimension, type 2).** Tiers are never edited in place — changing a tier closes the old row by stamping its `effectiveTo` and inserts a new row. The current tier set is what the tiers dialog manages (add / remove); the **price-tier history** dialog (the *history* affordance on a source) is read-only and shows **every** tier row, current and closed, sorted `effectiveFrom` DESC then `minQuantity` ASC — the audit trail of what was quoted/billed before. A **Show tier history** toggle on the Sources panel also greys-in superseded (closed) rows inline in the Inspector/Pricing views.\n\nThe quantity-break selection rule (highest `minQuantity` still ≤ requested qty, among tiers active on the date) only ever considers rows whose `effectiveTo` is null or in the future — closed rows are history only.\n\n## Landed Cost & Manual Override\n\nThe **Cost** tab's landed-cost surface computes a **\"door to door\" averaged unit cost** over the most recent N receipts (default 3): an itemized breakdown of **base + freight + duty + FX**, the contributing receipts as a sparse table, and a vendor comparison so the buyer can spot a cheaper source. When no receipt has captured freight yet, it shows an empty state instead of a misleading number.\n\nLanded cost is computed, not stored as the cost of record. The **Manual Cost Override** (`manualCostOverride`) is a single currency field that, when set, takes precedence over the calculated landed/standard cost everywhere downstream (margin math, valuation). Clearing it (empty or negative input saves null) reverts to the calculated value. `currentCostCalculationId` is the read-only snapshot id the background cost job recomputes whenever a BOM line, vendor source, or price changes — either it OR a manual override satisfies the **Cost** readiness gate.\n\n## Canonical Material & UoM Units\n\n**Material** measurements are stored in **canonical SI units** with a separate display-unit column so entry round-trips losslessly:\n\n- **Weight** → canonical **grams**; display unit one of g / kg / oz / lb.\n- **Length / Width / Height** → canonical **millimeters**; display unit mm / cm / m / in / ft.\n- **Volume** → canonical **milliliters**; display unit mL / L / oz / gal.\n\nThe user types in their preferred unit; the system converts to canonical for storage and back to the entry unit for display, so the typed value and unit are preserved exactly.\n\n**UoM** is three distinct lookup-backed units: **Stock** (the canonical inventory unit, also the unit the readiness Inventory gate checks via `stockUomId`), **Purchase** (may differ — e.g. stock by piece, purchase by case), and **Sales**. A source's price tier carries its own `purchaseUnitId` and a content qty per purchase unit, which is how the Pricing view normalizes every tier to a comparable per-base-unit price.\n\n## Purchase History & 3D Viewer Tabs\n\n**Purchase History** is a read-only tab listing the most recent POs that included this part. It has its own search box and a fetched-row **cap** indicator (it shows the count, not an unbounded history) — it's a quick \"what have we paid and when\", not a reporting surface.\n\n**3D Viewer** is a **conditional** tab — it only appears when a `.stl` file is attached to the part (detected by filename on the Files list). It renders the model via the shared `<app-stl-viewer>`. Both the Viewer and Serials tabs are *independent* extras outside the resolver-driven tab set: they're added by the panel itself based on STL-presence and Traceability = Serial, and they survive even when the resolved core tab list wouldn't otherwise include them.\n\n## Serial Genealogy\n\nOn a serial-tracked part (Traceability = Serial), opening a serial's detail and clicking **Genealogy** opens an `account_tree` tree view of that serial's **parent/child hierarchy** — the *as-built* lineage of which serialized sub-assemblies were consumed into this unit, traced down through the build. It is distinct from two neighbors it's easily confused with: the serial's **History** panel (a flat chronological movement/lifecycle log — action, from/to location, timestamp) and the part's **BOM revision history** (the *definitional* component list, not the as-built one). Genealogy answers \"what physical serialized parts are inside this exact unit?\"; BOM revisions answer \"what was this assembly *supposed* to be made of, and when did that spec change?\".\n\n## Per-Combo Workflow Step Differences\n\nThe New Part fork picks a workflow definition from the chosen (procurement × inventory class) **combo**, and the combos are codenamed by procurement letter: **M1–M4** (Make × 4 classes), **B1–B6** (Buy × 6 classes), **S1–S2** (Subcontract × 2 classes), **P1 / P3** (Phantom × 2 classes — Phantom offers only Subassembly/FinishedGood, never Raw/Component/Consumable). Each combo declares its own required steps, which is also why each combo's promotion readiness gates differ.\n\nThe fork **recommends** a path per combo: lightweight combos (e.g. **B1** Buy+Raw, **P3** Phantom+FinishedGood) recommend the single-page **express** form; assembly/sourcing-heavy combos (e.g. **M2** Make+Subassembly, **S1** Subcontract+Component) recommend the multi-step **guided** workflow. The available step components include Basics, Inventory, Quality, Sourcing, Vendor, Vendor-Parts, Costing, BOM, Routing, Alternates, Flags, Sales-Hooks, Shipping, Tool-Asset, and Source-Part — but any given combo only walks the subset its definition declares (a Buy+Consumable never sees Routing; a Make+FinishedGood does). Today two definitions back the system (assembly-guided + raw-material-express) with the axes populated; per-combo definitions are the Pillar 6 buildout.","sections":[]}"""
        });

        Log.Information("Seeded Parts training modules");
    }
}
